import java.util.Scanner;

public class BufferOverflowExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Set a maximum buffer size to prevent buffer overflow
        int bufferSize = 10;

        char[] buffer = new char[bufferSize];

        // Check if input length exceeds buffer size
        if (userInput.length() > bufferSize) {
            System.out.println("Input string exceeds buffer size. Truncating...");
            userInput = userInput.substring(0, bufferSize); // Truncate input to fit buffer size
        }

        // Copy input into the buffer
        for (int i = 0; i < userInput.length(); i++) {
            buffer[i] = userInput.charAt(i);
        }

        System.out.println("Buffer contents: " + String.valueOf(buffer));
    }
}

